import React, { useEffect, useState } from "react";
import { useParams } from "react-router-dom";

import Card from "../../shared/components/UIElements/Card";
import Input from "../../shared/components/FormElements/Input";
import Button from "../../shared/components/FormElements/Button";
import { VALIDATOR_REQUIRE, VALIDATOR_MINLENGTH } from "../../shared/components/util/validators";
import { useForm } from "../../shared/components/hooks/form-hook";

import './PlaceForm.css';

const DUMMY_PLACES = [
   {
        id: "p1",
        title: "Dubai – Stad van records en glitter",
        description: "One of the most famous sky scrapers in the world!",
        imageUrl: "https://travelizi.nl/sites/default/files/inline-images/Atlantis%2C%20The%20Palm%2C%20Dubai-faisal-manga-4NeuZU-ynnw-unsplash.jpg",
        address: "Midtown Manhattan, Fifth Avenue at 34th Street, New York City.",
        location: { lat: 40.7484405, lng: -73.9878584 },
        creator: "u1"
    },
    {
        id: "p2",
        title: "New York City (Statue of Liberty)",
        description: "There are different geographical, cultural, financial, and political aspects to consider.",
        imageUrl: "https://www.westernunion.com/blogs-staticassets/R25-07.05.0-161/media/Travel_Spotlight_USA_02.jpg",
        location: { lat: 40.6892494, lng: 74.0470753 },
        creator: "u2"
    }
    // ... baki places bhi yahan add kar sakte hain
];

const UpdatePlace = () => {
    const [isLoading, setIsLoading] = useState(false);
    const placeId = useParams().placeId;

    const [formState, inputHandler, setFormData] = useForm({
        title: {
            value: '',
            isValid: false
        },
        description: {
            value: '',
            isValid:false
        }
    }, false);

    const identifiedPlace = DUMMY_PLACES.find(p => p.id === placeId);
    
    useEffect(() => {
  if (identifiedPlace) {
    setFormData(
      {
        title: {
          value: identifiedPlace.title,
          isValid: true
        },
        description: {
          value: identifiedPlace.description,
          isValid: true
        }
      },
      true
    );
    setIsLoading(false);
  }
}, [setFormData, identifiedPlace]);


    const placeUpdateSubmitHandler = event => {
  event.preventDefault();
  console.log(formState.inputs);
};


    if (!identifiedPlace) {
        return (
            <div className="center">
                <Card>
                <h2>Could not find place!</h2>
                </Card>
            </div>
        );
    }

    if (isLoading) {
        return (
            <div className="center">
                <h2>Loading....</h2>
            </div>
        );
    }
    

    return <form className="place-form" onSubmit={placeUpdateSubmitHandler}>
        <Input 
        
        id="title" 
        element="input" 
        type="text"
        label="Title"
        validators={[VALIDATOR_REQUIRE]}
        errorText="please enter a valid title."
        onInput={inputHandler}
        initialValue={formState.inputs.title.value}
        initialValid={formState.inputs.title.isValid}
        />
        <Input 
        
        id="description" 
        element="textarea" 
        label="Description"
        validators={[VALIDATOR_MINLENGTH(5)]}
        errorText="please enter a valid description (at least 5 characters)."
       onInput={inputHandler}
        initialValue={formState.inputs.description.value}
        initialValid={formState.inputs.description.isValid}
        />
        <Button type="submit" disabled={!formState.isValid}>UPDATE PLACE</Button>
    </form>
};

export default UpdatePlace;
